      if (!detail) {
        res.statusCode = 404;
        res.setHeader('Content-Type', 'application/json');
        res.end(JSON.stringify({ error: 'Timeline detail not found' }));
        return true;
      }

      res.statusCode = 200;
      res.setHeader('Content-Type', 'application/json');
      res.end(JSON.stringify(detail));
      return true;
    } catch (error) {
      logger.error(`Failed to get timeline detail: ${error}`);
