                document.getElementById('requests-list').innerHTML = html;
            } catch (error) { document.getElementById('requests-list').innerHTML = '<div class="error">Failed: ' + error.message + '</div>'; }
        }

        async function showAnalysis(runId) {
            try {
                const response = await fetch('/plugins/contextscope/api/analysis?runId=' + runId);
                const analysis = await response.json();
                if (analysis.error) { alert('Failed: ' + analysis.error); return; }
                currentAnalysis = analysis;
                document.getElementById('modal-title').textContent = 'Analysis: ' + analysis.provider + ' / ' + analysis.model;
                const tokenDetailCtx = document.getElementById('tokenDetailChart').getContext('2d');
                if (tokenDetailChart) tokenDetailChart.destroy();
                tokenDetailChart = new Chart(tokenDetailCtx, { type: 'bar', data: { labels: analysis.tokenBreakdown.labels, datasets: [{ label: 'Tokens', data: analysis.tokenBreakdown.values, backgroundColor: analysis.tokenBreakdown.colors, borderRadius: 4 }] }, options: { responsive: true, maintainAspectRatio: false, scales: { y: { beginAtZero: true, ticks: { color: getComputedStyle(document.body).getPropertyValue('--text-secondary') }, grid: { color: getComputedStyle(document.body).getPropertyValue('--border') } }, x: { ticks: { color: getComputedStyle(document.body).getPropertyValue('--text-secondary') }, grid: { display: false } } } } });
                renderHeatmap(analysis.heatmap);
                renderTimeline(analysis.timeline);
                renderDependencyGraph(analysis.dependencyGraph);
                renderInsights(analysis.insights);
                document.getElementById('analysis-modal').classList.add('active');
                switchTab('token');
            } catch (error) { alert('Failed: ' + error.message); }
        }

        function renderHeatmap(heatmap) {
            const container = document.getElementById('heatmap-container');
            if (!heatmap.messages || heatmap.messages.length === 0) { container.innerHTML = '<div class="empty-state">No message data</div>'; return; }
            const rows = [];
            for (let i = 0; i < heatmap.messages.length; i += 10) rows.push(heatmap.messages.slice(i, i + 10));
            let html = '';
            rows.forEach(row => {
                html += '<div class="heatmap-row">';
                row.forEach(msg => {
                    const intensity = msg.impact / heatmap.maxImpact;
                    const r = Math.round(88 + (210 - 88) * intensity);
                    const g = Math.round(166 + (153 - 166) * intensity);
                    const b = Math.round(255 + (34 - 255) * intensity);
                    html += '<div class="heatmap-cell" style="background: rgb(' + r + ',' + g + ',' + b + ');" title="Role: ' + msg.role + ', Tokens: ' + msg.tokens + ', Impact: ' + msg.impact + '">' + msg.tokens + '</div>';
                });
                html += '</div>';
            });
            container.innerHTML = html;
        }

        function renderTimeline(timeline) {
            const container = document.getElementById('timeline-container');
            if (!timeline.points || timeline.points.length === 0) { container.innerHTML = '<div class="empty-state">No timeline data</div>'; return; }
            let html = '';
            timeline.points.forEach(point => {
                const time = new Date(point.timestamp).toLocaleString();
                const cls = point.utilization > 0.9 ? 'danger' : point.utilization > 0.7 ? 'warning' : '';
                html += '<div class="timeline-point ' + cls + '"><div class="timeline-content"><div style="font-size:0.8rem;color:var(--text-secondary);">' + time + '</div><div style="display:flex;gap:16px;font-size:0.85rem;"><span>Tokens: <strong>' + point.tokens.toLocaleString() + '</strong></span><span>Messages: <strong>' + point.messages + '</strong></span><span>Utilization: <strong>' + Math.round(point.utilization * 100) + '%</strong></span></div><div class="progress-bar" style="margin-top:8px;"><div class="progress-fill" style="width:' + Math.min(100, point.utilization * 100) + '%"></div></div></div></div>';
            });
            container.innerHTML = html;
        }

        function renderDependencyGraph(graph) {
            const container = document.getElementById('graph-nodes');
            if (!graph.nodes || graph.nodes.length === 0) { container.innerHTML = '<div class="empty-state">No tool call data</div>'; return; }
            let html = '';
            graph.nodes.forEach(node => {
                html += '<div class="graph-node ' + node.status + '"><div style="font-weight:600;margin-bottom:8px;">' + node.label + '</div><div style="font-size:0.8rem;color:var(--text-secondary);"><div>Tokens: ' + node.tokens.toLocaleString() + '</div><div>Duration: ' + node.duration + 'ms</div><div>Status: ' + (node.status === 'success' ? '✅' : node.status === 'error' ? '❌' : '⏳') + '</div></div></div>';
            });
            container.innerHTML = html;
        }

        function renderInsights(insights) {
            const container = document.getElementById('insights-container');
            if (!insights || insights.length === 0) { container.innerHTML = '<div class="empty-state">No insights</div>'; return; }
            let html = '';
            insights.forEach(insight => {
                const cls = insight.type === 'warning' ? 'insight-warning' : insight.type === 'optimization' ? 'insight-optimization' : 'insight-info';
                const icon = insight.type === 'warning' ? '⚠️' : insight.type === 'optimization' ? '💡' : 'ℹ️';
                html += '<div class="insight-item ' + cls + '"><div style="font-weight:600;margin-bottom:4px;">' + icon + ' ' + insight.title + '</div><div style="font-size:0.9rem;color:var(--text-secondary);">' + insight.description + '</div></div>';
            });
            container.innerHTML = html;
        }

        function closeModal() { document.getElementById('analysis-modal').classList.remove('active'); currentAnalysis = null; }
        function switchTab(tabName) { document.querySelectorAll('.tab').forEach(t => t.classList.remove('active')); document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active')); event.target.classList.add('active'); document.getElementById('tab-' + tabName).classList.add('active'); }
        function refreshData() { loadStats(); loadRequests(); }
        function exportData(format) { window.open('/plugins/contextscope/api/export?format=' + format, '_blank'); }
        document.getElementById('analysis-modal').addEventListener('click', function(e) { if (e.target === this) closeModal(); });
        refreshData();
        ${autoRefresh ? 'if (refreshTimer) clearInterval(refreshTimer); refreshTimer = setInterval(refreshData, ' + refreshInterval + ');' : ''}
    </script>
</body>
</html>`;
  }
}

/**
 * Context Analyzer Module
 * 
 * Provides deep analysis of request contexts including:
 * - Token distribution analysis
 * - Attention heatmap calculation
 * - Context evolution tracking
 * - Tool call dependency graph
 */

import type { RequestData } from './storage.js';

export interface TokenBreakdown {
  systemPrompt: number;
  historyMessages: number;
  currentPrompt: number;
  toolResponses: number;
  totalInput: number;
  output: number;
  cacheRead: number;
  cacheWrite: number;
}

export interface MessageImpact {
  messageId: string;
  role: 'user' | 'assistant' | 'system';
  content: string;
  tokenCount: number;
  impactScore: number; // 0-100
  timestamp: number;
}

export interface ContextEvolution {
  timestamp: number;
  totalTokens: number;
  messageCount: number;
  compressionRatio: number;
  summaryApplied: boolean;
  windowUtilization: number; // 0-1
}

export interface ToolCallNode {
  id: string;
  name: string;
  duration: number;
  tokensUsed: number;
  dependencies: string[];
  status: 'success' | 'error' | 'pending';
  children: string[];
}

export interface DependencyGraph {
  nodes: ToolCallNode[];
  edges: Array<{ from: string; to: string; weight: number }>;
}

export interface AnalysisResult {
  runId: string;
  sessionId: string;
  tokenBreakdown: TokenBreakdown;
  messageImpacts: MessageImpact[];
  contextEvolution: ContextEvolution[];
  dependencyGraph: DependencyGraph;
  insights: AnalysisInsight[];
  // Context Analysis
  topicClusters: TopicCluster[];
  contextSimilarities: ContextSimilarity[];
  compressionSuggestions: ContextCompressionSuggestion[];
  attentionDistribution: AttentionDistribution;
  keyMessages: MessageImpact[];
  contextHealth: {
    score: number; // 0-100
    issues: string[];
    recommendations: string[];
  };
}

export interface AnalysisInsight {
  type: 'warning' | 'info' | 'optimization';
  title: string;
  description: string;
  severity: 'low' | 'medium' | 'high';
}

export interface ContextSimilarity {
  messageId: string;
  similarTo: string;
  similarityScore: number; // 0-1
  topic: string;
}

export interface TopicCluster {
  topic: string;
  messageIds: string[];
  keywords: string[];
  percentage: number;
}

export interface ContextCompressionSuggestion {
  type: 'remove' | 'summarize' | 'keep';
  messageId: string;
  reason: string;
  tokenSavings: number;
  impact: 'low' | 'medium' | 'high';
}

export interface AttentionDistribution {
  systemPrompt: number; // 0-1
  recentMessages: number; // 0-1
  olderMessages: number; // 0-1
  toolResponses: number; // 0-1
}

export class ContextAnalyzer {
  private readonly MODEL_CONTEXT_WINDOWS: Record<string, number> = {
    'gpt-4': 8192,
    'gpt-4-turbo': 128000,
    'gpt-4-32k': 32768,
    'gpt-3.5-turbo': 16385,
    'gpt-3.5-turbo-16k': 16385,
    'claude-3-opus': 200000,
    'claude-3-sonnet': 200000,
    'claude-3-haiku': 200000,
    'claude-2': 100000,
    'qwen': 32768,
    'qwen2': 128000,
    'default': 8192
  };

  private readonly STOP_WORDS = new Set(['the', 'a', 'an', 'is', 'are', 'was', 'were', 'be', 'been', 'being', 'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would', 'could', 'should', 'may', 'might', 'must', 'shall', 'can', 'need', 'dare', 'ought', 'used', 'to', 'of', 'in', 'for', 'on', 'with', 'at', 'by', 'from', 'as', 'into', 'through', 'during', 'before', 'after', 'above', 'below', 'between', 'under', 'again', 'further', 'then', 'once', 'here', 'there', 'when', 'where', 'why', 'how', 'all', 'each', 'few', 'more', 'most', 'other', 'some', 'such', 'no', 'nor', 'not', 'only', 'own', 'same', 'so', 'than', 'too', 'very', 'just', 'and', 'but', 'if', 'or', 'because', 'until', 'while', 'although', 'though', 'after', 'before', 'when', 'whenever', 'where', 'wherever', 'whether', 'which', 'while', 'who', 'whoever', 'whom', 'whose', 'what', 'whatever', 'that', 'this', 'these', 'those', 'i', 'you', 'he', 'she', 'it', 'we', 'they', 'me', 'him', 'her', 'us', 'them', 'my', 'your', 'his', 'its', 'our', 'their', 'mine', 'yours', 'hers', 'ours', 'theirs', 'myself', 'yourself', 'himself', 'herself', 'itself', 'ourselves', 'themselves']);

  analyzeRequest(request: RequestData, relatedRequests: RequestData[]): AnalysisResult {
    const tokenBreakdown = this.analyzeTokenDistribution(request);
    const messageImpacts = this.analyzeMessageImpacts(request);
    const contextEvolution = this.analyzeContextEvolution(relatedRequests);
    const dependencyGraph = this.analyzeToolDependencies(relatedRequests);
    const insights = this.generateInsights(tokenBreakdown, messageImpacts, contextEvolution);

    // Context Analysis
    const topicClusters = this.analyzeTopicClusters(request);
    const contextSimilarities = this.analyzeContextSimilarities(request);
    const compressionSuggestions = this.generateCompressionSuggestions(request, messageImpacts);
    const attentionDistribution = this.analyzeAttentionDistribution(request);
    const keyMessages = this.extractKeyMessages(messageImpacts);
    const contextHealth = this.calculateContextHealth(request, messageImpacts, tokenBreakdown);

    return {
      runId: request.runId,
      sessionId: request.sessionId,
      tokenBreakdown,
      messageImpacts,
      contextEvolution,
      dependencyGraph,
      insights,
      topicClusters,
      contextSimilarities,
      compressionSuggestions,
      attentionDistribution,
      keyMessages,
      contextHealth
    };
  }

  private analyzeTokenDistribution(request: RequestData): TokenBreakdown {
    const breakdown: TokenBreakdown = {
      systemPrompt: 0,
      historyMessages: 0,
      currentPrompt: 0,
      toolResponses: 0,
      totalInput: 0,
      output: 0,
      cacheRead: 0,
      cacheWrite: 0
    };

    // Estimate token counts based on content length
    if (request.systemPrompt) {
      breakdown.systemPrompt = this.estimateTokens(request.systemPrompt);
    }

    if (request.historyMessages) {
      const historyContent = JSON.stringify(request.historyMessages);
      breakdown.historyMessages = this.estimateTokens(historyContent);
    }

    if (request.prompt) {
      breakdown.currentPrompt = this.estimateTokens(request.prompt);
    }

    // Analyze tool responses in history
    if (request.historyMessages) {
      for (const msg of request.historyMessages) {
        const msgAny = msg as any;
        if (msgAny?.role === 'tool' || msgAny?.type === 'tool_response') {
          const content = typeof msgAny.content === 'string' ? msgAny.content : JSON.stringify(msgAny.content);
          breakdown.toolResponses += this.estimateTokens(content);
        }
      }
    }

    breakdown.totalInput = breakdown.systemPrompt + breakdown.historyMessages + 
                           breakdown.currentPrompt + breakdown.toolResponses;

    if (request.usage) {
      breakdown.output = request.usage.output || 0;
      breakdown.cacheRead = request.usage.cacheRead || 0;
      breakdown.cacheWrite = request.usage.cacheWrite || 0;
    }

    return breakdown;
  }

  private analyzeMessageImpacts(request: RequestData): MessageImpact[] {
    const impacts: MessageImpact[] = [];

    if (!request.historyMessages) return impacts;

    const now = request.timestamp;
    const halfLife = 30 * 60 * 1000; // 30 minutes half-life

    request.historyMessages.forEach((msg: any, index: number) => {
      const content = typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content);
      const tokenCount = this.estimateTokens(content);

      // Calculate impact score based on:
      // - Recency (exponential decay)
      // - Content length (longer = potentially more important)
      // - Position (later messages often more relevant)
      const timeDecay = Math.exp(-(now - (msg.timestamp || now)) / halfLife);
      const lengthFactor = Math.log10(tokenCount + 10);
      const positionFactor = (index + 1) / request.historyMessages!.length;

      const impactScore = Math.round(
        (timeDecay * 0.5 + lengthFactor * 0.3 + positionFactor * 0.2) * 100
      );

      impacts.push({
        messageId: msg.id || `msg-${index}`,
        role: msg.role || 'user',
        content: content.substring(0, 200) + (content.length > 200 ? '...' : ''),
        tokenCount,
        impactScore: Math.min(100, Math.max(0, impactScore)),
        timestamp: msg.timestamp || now
      });
    });

    // Sort by impact score descending
    impacts.sort((a, b) => b.impactScore - a.impactScore);

    return impacts;
  }

  private analyzeContextEvolution(requests: RequestData[]): ContextEvolution[] {
    const evolution: ContextEvolution[] = [];
    const sortedRequests = [...requests].sort((a, b) => a.timestamp - b.timestamp);

    let cumulativeTokens = 0;
    let messageCount = 0;

    sortedRequests.forEach((request, index) => {
      const tokens = request.usage?.total || 
                     this.estimateTokens(request.prompt || '') + 
                     this.estimateTokens(request.systemPrompt || '');

      cumulativeTokens += tokens;
      messageCount++;

      const modelWindow = this.getModelContextWindow(request.model);
      const compressionRatio = cumulativeTokens / modelWindow;
      const summaryApplied = compressionRatio > 0.8;

      evolution.push({
        timestamp: request.timestamp,
        totalTokens: cumulativeTokens,
        messageCount,
        compressionRatio: Math.min(1, compressionRatio),
        summaryApplied,
        windowUtilization: compressionRatio
      });

      // If compression ratio exceeded, simulate context compression
      if (compressionRatio > 1) {
        cumulativeTokens = Math.round(modelWindow * 0.7); // Compress to 70% after summary
      }
    });

    return evolution;
  }

  private analyzeToolDependencies(requests: RequestData[]): DependencyGraph {
    const nodes: Map<string, ToolCallNode> = new Map();
    const edges: Array<{ from: string; to: string; weight: number }> = [];

    requests.forEach((request, index) => {
      // Extract tool calls from history messages
      if (request.historyMessages) {
        request.historyMessages.forEach((msg: any) => {
          if (msg.tool_call_id || msg.type === 'tool_call') {
            const nodeId = msg.tool_call_id || `tool-${Date.now()}-${Math.random()}`;
            const toolName = msg.name || msg.tool_name || 'unknown';

            if (!nodes.has(nodeId)) {
              nodes.set(nodeId, {
                id: nodeId,
                name: toolName,
                duration: msg.duration || 0,
                tokensUsed: this.estimateTokens(JSON.stringify(msg)),
                dependencies: [],
                status: msg.status || 'success',
                children: []
              });
            }
          }

          // Track tool call relationships
          if (msg.tool_call_id && msg.role === 'tool') {
            // This is a tool response, link to the original call
            const responseId = `response-${msg.tool_call_id}`;
            nodes.set(responseId, {
              id: responseId,
              name: `${msg.name || 'tool'}-response`,
              duration: 0,
              tokensUsed: this.estimateTokens(typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content)),
              dependencies: [msg.tool_call_id],
              status: 'success',
              children: []
            });

            edges.push({
              from: msg.tool_call_id,
              to: responseId,
              weight: 1
            });
          }
        });
      }

      // Track sequential tool calls as dependencies
      if (request.metadata && (request.metadata as any).toolCalls) {
        const toolCalls = (request.metadata as any).toolCalls as any[];
        toolCalls.forEach((call: any, idx: number) => {
          const callId = call.id || `call-${index}-${idx}`;

          if (!nodes.has(callId)) {
            nodes.set(callId, {
              id: callId,
              name: call.name || 'unknown',
              duration: call.duration || 0,
              tokensUsed: call.tokens || 0,
              dependencies: idx > 0 ? [toolCalls[idx - 1].id || `call-${index}-${idx - 1}`] : [],
              status: call.status || 'success',
              children: []
            });
          }

          // Add edge from previous tool call
          if (idx > 0) {
            const prevId = toolCalls[idx - 1].id || `call-${index}-${idx - 1}`;
            edges.push({
              from: prevId,
              to: callId,
              weight: 1
            });
          }
        });
      }
    });

    // Build children arrays from dependencies
    edges.forEach(edge => {
      const fromNode = nodes.get(edge.from);
      if (fromNode) {
        fromNode.children.push(edge.to);
      }
    });

    return {
      nodes: Array.from(nodes.values()),
      edges
    };
  }

  private generateInsights(
    tokenBreakdown: TokenBreakdown,
    messageImpacts: MessageImpact[],
    contextEvolution: ContextEvolution[]
  ): AnalysisInsight[] {
    const insights: AnalysisInsight[] = [];

    // Check for high token usage in system prompt
    if (tokenBreakdown.systemPrompt > tokenBreakdown.totalInput * 0.3) {
      insights.push({
        type: 'optimization',
        title: '系统提示占用过高',
        description: `系统提示占用了 ${Math.round(tokenBreakdown.systemPrompt / tokenBreakdown.totalInput * 100)}% 的输入 token，考虑优化或压缩系统提示`,
        severity: 'medium'
      });
    }

    // Check for context window pressure
    const latestEvolution = contextEvolution[contextEvolution.length - 1];
    if (latestEvolution && latestEvolution.windowUtilization > 0.8) {
      insights.push({
        type: 'warning',
        title: '上下文窗口压力大',
        description: `上下文窗口使用率已达 ${Math.round(latestEvolution.windowUtilization * 100)}%，可能触发自动摘要或截断`,
        severity: latestEvolution.windowUtilization > 0.95 ? 'high' : 'medium'
      });
    }

    // Check for low-impact messages consuming tokens
    const lowImpactHighToken = messageImpacts.filter(
      m => m.impactScore < 30 && m.tokenCount > 100
    );
    if (lowImpactHighToken.length > 0) {
      insights.push({
        type: 'optimization',
        title: '低价值消息占用上下文',
        description: `发现 ${lowImpactHighToken.length} 条低影响力但占用较多 token 的消息，考虑从上下文中移除`,
        severity: 'low'
      });
    }

    // Check for cache efficiency
    if (tokenBreakdown.cacheRead > 0 && tokenBreakdown.cacheWrite > 0) {
      const cacheHitRate = tokenBreakdown.cacheRead / (tokenBreakdown.cacheRead + tokenBreakdown.cacheWrite);
      if (cacheHitRate < 0.5) {
        insights.push({
          type: 'info',
          title: '缓存命中率较低',
          description: `缓存命中率仅为 ${Math.round(cacheHitRate * 100)}%，考虑优化提示结构以提高缓存效率`,
          severity: 'low'
        });
      }
    }

    return insights;
  }

  private estimateTokens(text: string): number {
    // Simple estimation: ~4 characters per token for English
    // For Chinese, ~1.5 characters per token
    const chineseChars = (text.match(/[\u4e00-\u9fa5]/g) || []).length;
    const otherChars = text.length - chineseChars;

    return Math.round(chineseChars / 1.5 + otherChars / 4);
  }

  private getModelContextWindow(model: string): number {
    const modelLower = model.toLowerCase();
    for (const [key, value] of Object.entries(this.MODEL_CONTEXT_WINDOWS)) {
      if (modelLower.includes(key)) {
        return value;
      }
    }
    return this.MODEL_CONTEXT_WINDOWS['default'];
  }

  /**
   * Analyze topic clusters in the conversation
   */
  private analyzeTopicClusters(request: RequestData): TopicCluster[] {
    const clusters: TopicCluster[] = [];
    const messages = request.historyMessages || [];

    if (messages.length === 0) return clusters;

    // Extract keywords from each message
    const messageKeywords = messages.map((msg: any) => {
      const content = typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content);
      const words = content.toLowerCase()
        .replace(/[^\w\s]/g, ' ')
        .split(/\s+/)
        .filter((w: string) => w.length > 3 && !this.STOP_WORDS.has(w));

      const wordFreq: Record<string, number> = {};
      words.forEach((w: string) => wordFreq[w] = (wordFreq[w] || 0) + 1);

      return {
        messageId: msg.id || `msg-${messages.indexOf(msg)}`,
        keywords: Object.entries(wordFreq)
          .sort((a, b) => b[1] - a[1])
          .slice(0, 5)
          .map(([word]) => word),
        content
      };
    });

    // Group by common keywords (simple clustering)
    const allKeywords = new Set<string>();
    messageKeywords.forEach(mk => mk.keywords.forEach(k => allKeywords.add(k)));

    const keywordToMessages: Record<string, string[]> = {};
    allKeywords.forEach(keyword => {
      keywordToMessages[keyword] = messageKeywords
        .filter(mk => mk.keywords.includes(keyword))
        .map(mk => mk.messageId);
    });

    // Create clusters from top keywords
    const topKeywords = Array.from(allKeywords).slice(0, 5);
    const totalMessages = messages.length;

    topKeywords.forEach(keyword => {
      const msgIds = keywordToMessages[keyword];
      if (msgIds.length > 0) {
        clusters.push({
          topic: keyword,
          messageIds: msgIds,
          keywords: [keyword],
          percentage: Math.round((msgIds.length / totalMessages) * 100)
        });
      }
    });

    return clusters;
  }

  /**
   * Analyze similarity between messages
   */
  private analyzeContextSimilarities(request: RequestData): ContextSimilarity[] {
    const similarities: ContextSimilarity[] = [];
    const messages = request.historyMessages || [];

    if (messages.length < 2) return similarities;

    // Simple Jaccard similarity based on word overlap
    for (let i = 0; i < messages.length; i++) {
      for (let j = i + 1; j < messages.length; j++) {
        const msg1 = messages[i] as any;
        const msg2 = messages[j] as any;

        const content1 = typeof msg1.content === 'string' ? msg1.content : JSON.stringify(msg1.content);
        const content2 = typeof msg2.content === 'string' ? msg2.content : JSON.stringify(msg2.content);

        const words1 = new Set(content1.toLowerCase().split(/\s+/).filter((w: string) => w.length > 3));
        const words2 = new Set(content2.toLowerCase().split(/\s+/).filter((w: string) => w.length > 3));

        const intersection = new Set([...words1].filter(w => words2.has(w)));
        const union = new Set([...words1, ...words2]);

        const similarity = union.size > 0 ? intersection.size / union.size : 0;

        if (similarity > 0.3) { // Only report significant similarities
          const commonWords = Array.from(intersection).slice(0, 3).join(', ');
          similarities.push({
            messageId: msg1.id || `msg-${i}`,
            similarTo: msg2.id || `msg-${j}`,
            similarityScore: Math.round(similarity * 100) / 100,
            topic: commonWords
          });
        }
      }
    }

    return similarities.sort((a, b) => b.similarityScore - a.similarityScore).slice(0, 10);
  }

  /**
   * Generate context compression suggestions
   */
  private generateCompressionSuggestions(request: RequestData, messageImpacts: MessageImpact[]): ContextCompressionSuggestion[] {
    const suggestions: ContextCompressionSuggestion[] = [];
    const messages = request.historyMessages || [];

    messages.forEach((msg: any, index: number) => {
      const impact = messageImpacts.find(mi => mi.messageId === (msg.id || `msg-${index}`));
      const content = typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content);
      const tokenCount = this.estimateTokens(content);

      // Low impact, high token messages are candidates for removal
      if (impact && impact.impactScore < 30 && tokenCount > 200) {
        suggestions.push({
          type: 'remove',
          messageId: msg.id || `msg-${index}`,
          reason: 'Low impact message consuming significant tokens',
          tokenSavings: tokenCount,
          impact: 'low'
        });
      }

      // Old messages with medium impact could be summarized
      const msgTime = msg.timestamp || request.timestamp;
      const age = request.timestamp - msgTime;
      if (age > 30 * 60 * 1000 && impact && impact.impactScore >= 30 && impact.impactScore < 60) {
        suggestions.push({
          type: 'summarize',
          messageId: msg.id || `msg-${index}`,
          reason: 'Old message that could be summarized',
          tokenSavings: Math.round(tokenCount * 0.5),
          impact: 'medium'
        });
      }
    });

    // High impact messages should be kept
    messageImpacts.filter(m => m.impactScore >= 80).forEach(m => {
      suggestions.push({
        type: 'keep',
        messageId: m.messageId,
        reason: 'High impact message - keep in context',
        tokenSavings: 0,
        impact: 'high'
      });
    });

    return suggestions.sort((a, b) => b.tokenSavings - a.tokenSavings);
  }

  /**
   * Analyze attention distribution
   */
  private analyzeAttentionDistribution(request: RequestData): AttentionDistribution {
    const breakdown = this.analyzeTokenDistribution(request);
    const total = breakdown.totalInput || 1;

    // Estimate attention based on token distribution and recency
    return {
      systemPrompt: Math.round((breakdown.systemPrompt / total) * 100) / 100,
      recentMessages: 0.4, // Recent messages typically get more attention
      olderMessages: 0.2, // Older messages get less attention
      toolResponses: Math.round((breakdown.toolResponses / total) * 100) / 100
    };
  }

  /**
   * Extract key messages
   */
  private extractKeyMessages(messageImpacts: MessageImpact[]): MessageImpact[] {
    return messageImpacts
      .filter(m => m.impactScore >= 70)
      .sort((a, b) => b.impactScore - a.impactScore)
      .slice(0, 5);
  }

  /**
   * Calculate overall context health score
   */
  private calculateContextHealth(request: RequestData, messageImpacts: MessageImpact[], tokenBreakdown: TokenBreakdown): {
    score: number;
    issues: string[];
    recommendations: string[];
  } {
    const issues: string[] = [];
    const recommendations: string[] = [];
    let score = 100;

    // Check for topic drift
    const topicClusters = this.analyzeTopicClusters(request);
    if (topicClusters.length > 5) {
      issues.push('Conversation covers too many topics');
      recommendations.push('Consider focusing on fewer topics per conversation');
      score -= 10;
    }

    // Check for redundant messages
    const similarities = this.analyzeContextSimilarities(request);
    const highSimilarity = similarities.filter(s => s.similarityScore > 0.7);
    if (highSimilarity.length > 3) {
      issues.push('Multiple highly similar messages detected');
      recommendations.push('Remove or merge redundant messages');
      score -= 15;
    }

    // Check system prompt ratio
    const totalTokens = tokenBreakdown.totalInput || 1;
    const systemPromptRatio = tokenBreakdown.systemPrompt / totalTokens;
    if (systemPromptRatio > 0.3) {
      issues.push('System prompt takes up too much context');
      recommendations.push('Consider shortening or optimizing system prompt');
      score -= 20;
    }

    // Check for low-impact messages
    const lowImpact = messageImpacts.filter(m => m.impactScore < 30).length;
    if (lowImpact > messageImpacts.length * 0.3) {
      issues.push('Many low-impact messages in context');
      recommendations.push('Remove or summarize low-value messages');
      score -= 15;
    }

    // Check context window utilization
    const modelWindow = this.getModelContextWindow(request.model);
    const utilization = totalTokens / modelWindow;
    if (utilization > 0.9) {
      issues.push('Context window nearly full');
      recommendations.push('Apply compression or start new conversation');
      score -= 25;
    } else if (utilization > 0.7) {
      issues.push('Context window getting full');
      recommendations.push('Consider proactive compression');
      score -= 10;
    }

    return {
      score: Math.max(0, score),
      issues,
      recommendations
    };
  }
}

/**
 * ContextScope Storage Module
 * 
 * Handles persistent storage of request data using JSON files
 */

import path from 'node:path';
import fs from 'node:fs';

interface PluginLogger {
  debug?: (message: string) => void;
  info: (message: string) => void;
  warn: (message: string) => void;
  error: (message: string) => void;
}

export interface RequestData {
  id?: number;
  type: 'input' | 'output';
  runId: string;
  sessionId: string;
  sessionKey?: string;
  provider: string;
  model: string;
  timestamp: number;
  prompt?: string;
  systemPrompt?: string;
  historyMessages?: unknown[];
  assistantTexts?: string[];
  usage?: {
    input?: number;
    output?: number;
    cacheRead?: number;
    cacheWrite?: number;
    total?: number;
  };
  imagesCount?: number;
  metadata?: Record<string, unknown>;
}

export interface SubagentLinkData {
  id?: number;
  kind?: 'spawn' | 'send';
  parentRunId: string;
  childRunId?: string;
  parentSessionId?: string;
  parentSessionKey?: string;
  childSessionKey?: string;
  runtime?: 'subagent' | 'acp';
  mode?: 'run' | 'session';
  label?: string;
  toolCallId?: string;
  timestamp: number;
  endedAt?: number;
  outcome?: 'success' | 'error' | 'timeout' | 'aborted' | 'unknown';
  error?: string;
  metadata?: Record<string, unknown>;
}

export interface ToolCallData {
  id?: number;
  runId: string;
  sessionId?: string;
  sessionKey?: string;
  toolName: string;
  toolCallId?: string;
  timestamp: number;
  startedAt?: number;
  durationMs?: number;
  params?: Record<string, unknown>;
  result?: unknown;
  error?: string;
  metadata?: Record<string, unknown>;
}

export interface StorageStats {
  totalRequests: number;
  todayRequests: number;
  weekRequests: number;
  storageSize: string;
  oldestRequest?: number;
  newestRequest?: number;
}

export interface StorageOptions {
  workspaceDir: string;
  maxRequests: number;
  retentionDays: number;
  compression: boolean;
  logger: PluginLogger;
}

export class RequestAnalyzerStorage {
  private dataFile: string;
  private requests: RequestData[] = [];
  private subagentLinks: SubagentLinkData[] = [];
  private toolCalls: ToolCallData[] = [];
  private options: StorageOptions;
  private initialized = false;
  private nextId = 1;
  private nextLinkId = 1;
  private nextToolCallId = 1;

  constructor(options: StorageOptions) {
    this.options = options;
    this.dataFile = path.join(options.workspaceDir, 'requests.json');
  }

  async initialize(): Promise<void> {
    if (this.initialized) return;

    const dir = this.options.workspaceDir;

    try {
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }

      // Load existing data
      if (fs.existsSync(this.dataFile)) {
        const content = fs.readFileSync(this.dataFile, 'utf-8');
        const data = JSON.parse(content);
        this.requests = data.requests || [];
        this.subagentLinks = data.subagentLinks || [];
        this.toolCalls = data.toolCalls || [];
        this.nextId = data.nextId || (this.requests.length > 0 ? Math.max(...this.requests.map(r => r.id || 0)) + 1 : 1);
        this.nextLinkId = data.nextLinkId || (this.subagentLinks.length > 0 ? Math.max(...this.subagentLinks.map(r => r.id || 0)) + 1 : 1);
        this.nextToolCallId = data.nextToolCallId || (this.toolCalls.length > 0 ? Math.max(...this.toolCalls.map(r => r.id || 0)) + 1 : 1);
      }

      this.initialized = true;
      this.options.logger.info('ContextScope storage initialized');
    } catch (error) {
      this.options.logger.error(`Failed to initialize storage: ${error}`);
      throw error;
    }
  }

  private async persist(): Promise<void> {
    if (!this.initialized) return;

    try {
      const data = {
        requests: this.requests,
        subagentLinks: this.subagentLinks,
        toolCalls: this.toolCalls,
        nextId: this.nextId,
        nextLinkId: this.nextLinkId,
        nextToolCallId: this.nextToolCallId,
        lastUpdated: Date.now()
      };
      fs.writeFileSync(this.dataFile, JSON.stringify(data, null, 2), 'utf-8');
    } catch (error) {
      this.options.logger.error(`Failed to persist data: ${error}`);
    }
  }

  async captureRequest(data: RequestData): Promise<void> {
    if (!this.initialized) await this.initialize();

    try {
      const requestWithId: RequestData = {
        ...data,
        id: this.nextId++
      };

      this.requests.unshift(requestWithId); // Add to beginning for latest-first order

      // Cleanup old requests if needed
      this.cleanupOldRequests();

      // Persist to disk (debounced in production, but simple here)
      await this.persist();

    } catch (error) {
      this.options.logger.error(`Failed to capture request: ${error}`);
      throw error;
    }
  }

  async captureSubagentLink(data: SubagentLinkData): Promise<void> {
    if (!this.initialized) await this.initialize();

    try {
      const recordWithId: SubagentLinkData = {
        ...data,
        kind: data.kind ?? 'spawn',
        outcome: data.outcome ?? undefined,
        id: this.nextLinkId++
      };

      this.subagentLinks.unshift(recordWithId);
      this.cleanupOldRequests();
      await this.persist();
    } catch (error) {
      this.options.logger.error(`Failed to capture subagent link: ${error}`);
      throw error;
    }
  }

  async updateSubagentLinkByChildRunId(params: {
    childRunId: string;
    patch: Partial<Pick<SubagentLinkData, 'endedAt' | 'outcome' | 'error' | 'metadata'>>;
  }): Promise<void> {
    if (!this.initialized) await this.initialize();

    const childRunId = params.childRunId.trim();
    if (!childRunId) {
      return;
    }

    const idx = this.subagentLinks.findIndex(r => r.childRunId === childRunId);
    if (idx < 0) {
      return;
    }

    const current = this.subagentLinks[idx];
    const next: SubagentLinkData = {
      ...current,
      ...params.patch,
      metadata: {
        ...(current.metadata || {}),
        ...(params.patch.metadata || {})
      }
    };
    this.subagentLinks[idx] = next;
    await this.persist();
  }

  async captureToolCall(data: ToolCallData): Promise<void> {
    if (!this.initialized) await this.initialize();

    try {
      const recordWithId: ToolCallData = {
        ...data,
        id: this.nextToolCallId++
      };
      this.toolCalls.unshift(recordWithId);
      this.cleanupOldRequests();
      await this.persist();
    } catch (error) {
      this.options.logger.error(`Failed to capture tool call: ${error}`);
      throw error;
    }
  }

  async getRequests(filters: {
    sessionId?: string;
    runId?: string;
    provider?: string;
    model?: string;
    startTime?: number;
    endTime?: number;
    limit?: number;
    offset?: number;
  } = {}): Promise<RequestData[]> {
    if (!this.initialized) await this.initialize();

    let filtered = [...this.requests];

    if (filters.sessionId) {
      filtered = filtered.filter(r => r.sessionId === filters.sessionId);
    }
    if (filters.runId) {
      filtered = filtered.filter(r => r.runId === filters.runId);
    }
    if (filters.provider) {
      filtered = filtered.filter(r => r.provider === filters.provider);
    }
    if (filters.model) {
      filtered = filtered.filter(r => r.model === filters.model);
    }
    if (filters.startTime) {
      filtered = filtered.filter(r => r.timestamp >= filters.startTime!);
    }
    if (filters.endTime) {
      filtered = filtered.filter(r => r.timestamp <= filters.endTime!);
    }

    const offset = filters.offset || 0;
    const limit = filters.limit || 100;

    return filtered.slice(offset, offset + limit);
  }

  async getToolCalls(filters: {
    runId?: string;
    sessionId?: string;
    toolName?: string;
    startTime?: number;
    endTime?: number;
    limit?: number;
    offset?: number;
  } = {}): Promise<ToolCallData[]> {
    if (!this.initialized) await this.initialize();

    let filtered = [...this.toolCalls];

    if (filters.runId) {
      filtered = filtered.filter(r => r.runId === filters.runId);
    }
    if (filters.sessionId) {
      filtered = filtered.filter(r => r.sessionId === filters.sessionId);
    }
    if (filters.toolName) {
      filtered = filtered.filter(r => r.toolName === filters.toolName);
    }
    if (filters.startTime) {
      filtered = filtered.filter(r => r.timestamp >= filters.startTime!);
    }
    if (filters.endTime) {
      filtered = filtered.filter(r => r.timestamp <= filters.endTime!);
    }

    const offset = filters.offset || 0;
    const limit = filters.limit || 100;
    return filtered.slice(offset, offset + limit);
  }

  async getSubagentLinks(filters: {
    parentRunId?: string;
    childRunId?: string;
    parentSessionId?: string;
    limit?: number;
    offset?: number;
  } = {}): Promise<SubagentLinkData[]> {
    if (!this.initialized) await this.initialize();

    let filtered = [...this.subagentLinks];

    if (filters.parentRunId) {
      filtered = filtered.filter(r => r.parentRunId === filters.parentRunId);
    }
    if (filters.childRunId) {
      filtered = filtered.filter(r => r.childRunId === filters.childRunId);
    }
    if (filters.parentSessionId) {
      filtered = filtered.filter(r => r.parentSessionId === filters.parentSessionId);
    }

    const offset = filters.offset || 0;
    const limit = filters.limit || 100;
    return filtered.slice(offset, offset + limit);
  }

  async getStats(): Promise<StorageStats> {
    if (!this.initialized) await this.initialize();

    const now = Date.now();
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const weekAgo = new Date(today);
    weekAgo.setDate(weekAgo.getDate() - 7);

    const todayTime = today.getTime();
    const weekAgoTime = weekAgo.getTime();

    const totalRequests = this.requests.length;
    const todayRequests = this.requests.filter(r => r.timestamp >= todayTime).length;
    const weekRequests = this.requests.filter(r => r.timestamp >= weekAgoTime).length;
    const oldestRequest = this.requests.length > 0 ? this.requests[this.requests.length - 1].timestamp : undefined;

    return {
      totalRequests,
      todayRequests,
      weekRequests,
      storageSize: this.getDatabaseSize(),
      oldestRequest,
      newestRequest: now
    };
  }

  private getDatabaseSize(): string {
    try {
      if (!fs.existsSync(this.dataFile)) return '0 B';
      const stats = fs.statSync(this.dataFile);
      const bytes = stats.size;

      if (bytes < 1024) return `${bytes} B`;
      if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
      return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
    } catch {
      return '0 B';
    }
  }

  private cleanupOldRequests(): void {
    const cutoffTime = Date.now() - (this.options.retentionDays * 24 * 60 * 60 * 1000);

    // Remove old requests
    this.requests = this.requests.filter(r => r.timestamp >= cutoffTime);
    this.subagentLinks = this.subagentLinks.filter(r => r.timestamp >= cutoffTime);
    this.toolCalls = this.toolCalls.filter(r => r.timestamp >= cutoffTime);

    // Remove excess requests if over limit
    if (this.requests.length > this.options.maxRequests) {
      this.requests = this.requests.slice(0, this.options.maxRequests);
    }
    if (this.subagentLinks.length > this.options.maxRequests) {
      this.subagentLinks = this.subagentLinks.slice(0, this.options.maxRequests);
    }
    if (this.toolCalls.length > this.options.maxRequests) {
      this.toolCalls = this.toolCalls.slice(0, this.options.maxRequests);
    }
  }

  async close(): Promise<void> {
    await this.persist();
    this.initialized = false;
  }
}
